const data = $input.all() ?? [];
const data_string = JSON.stringify(data);
const data_json = JSON.parse(data_string) ?? [];

// Check for Dify errors first
const errorMsg = data_json[0]?.json?.error?.message ?? '';
if (errorMsg && (errorMsg.includes('404') || errorMsg.includes('not_found') || errorMsg.includes('Not Exists'))) {
  // Conversation expired — return empty to clear Redis ID on next GravaConversationID
  return { response: '', conversationID: '', out: [], error: 'conversation_expired' };
}

const data_json_text = data_json[0]?.json?.data ?? '';
const data_array = data_json_text ? data_json_text.split('\n') : [];

const out = [];
const msgParts = [];
let conversationID = "";

if (Array.isArray(data_array) && data_array.length > 0) {
  for (const item of data_array) {
    const t = item.replace('data:', '').trim();
    if (!t) continue;
    try {
      const t_json = JSON.parse(t);
      if (t_json.event === 'agent_thought') {
        if (t_json.thought) out.push(t_json);
        conversationID = t_json?.conversation_id ?? conversationID;
      } else if (t_json.event === 'agent_message' && t_json.answer) {
        msgParts.push(t_json.answer);
        conversationID = t_json?.conversation_id ?? conversationID;
      } else if (t_json.event === 'message' && t_json.answer) {
        msgParts.push(t_json.answer);
        conversationID = t_json?.conversation_id ?? conversationID;
      }
    } catch (error) {}
  }
}

const msg = msgParts.length > 0
  ? msgParts.join('')
  : out.map(item => item.thought ?? '').join(' ');

return { response: msg, conversationID, out };

