// Obtenha o texto da entrada
const inputText = $input.first().json.response || "";

// Separa em blocos por PARÁGRAFO (linha dupla), não por cada \n
// Isso mantém listas de bullets em uma única mensagem
const textBlocks = inputText
  .split(/\n\n+/)
  .map(block => block.trim())
  .filter(block => block !== "");

// Se ainda assim tiver muita coisa, agrupa em no máximo 3 mensagens
const MAX_MSGS = 3;
let groupedBlocks = textBlocks;
if (textBlocks.length > MAX_MSGS) {
  const chunkSize = Math.ceil(textBlocks.length / MAX_MSGS);
  groupedBlocks = [];
  for (let i = 0; i < textBlocks.length; i += chunkSize) {
    groupedBlocks.push(textBlocks.slice(i, i + chunkSize).join('\n'));
  }
}

// Obtenha o tipo da mensagem do nó 'SetFieldsBasic'
const type_msg = $('SetFieldsBasic').first().json.type;

// Função para identificar o tipo de mídia com base no link ou no argumento 'tipo'
const determineMediaType = (url) => {
  const tipoMatch = url.match(/[?&]tipo=([^&]+)/);
  if (tipoMatch) return tipoMatch[1].replace(')','').replace('(','');
  const pdfRegex = /\.pdf$/i;
  const docRegex = /\.(doc|docx)$/i;
  const imageRegex = /\.(jpg|jpeg|png|gif|bmp|svg|webp)$/i;
  const videoRegex = /\.(mp4|mov|avi|wmv|mkv|flv|webm)$/i;
  const audioRegex = /\.(mp3|wav|ogg|m4a)$/i;
  if (pdfRegex.test(url)) return 'pdf';
  if (docRegex.test(url)) return 'doc';
  if (imageRegex.test(url)) return 'image';
  if (videoRegex.test(url)) return 'video';
  if (audioRegex.test(url)) return 'audioMessage';
  return null;
};

const extractUrl = (text) => {
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const match = text.match(urlRegex);
  return match ? match[0] : null;
};

let outputArray = [];

groupedBlocks.forEach((block, index) => {
  const url = extractUrl(block);
  const mediaType = url ? determineMediaType(url) : null;

  if (index === 0) {
    outputArray.push({
      type: mediaType && mediaType !== 'audioMessage' ? mediaType : 'conversation',
      text: block,
      url: url,
      mediaType: mediaType
    });
  } else {
    outputArray.push({
      type: mediaType && mediaType !== 'audioMessage' ? mediaType : 'conversation',
      text: block,
      url: url,
      mediaType: mediaType
    });
  }
});

if (outputArray.length === 0) return [];
return outputArray.map(item => ({ json: item }));

